// src/views/BarDisplayView.js
import React, { useState, useEffect } from 'react';

// Datos de ejemplo de pedidos que llegarían vía WebSockets
const incomingOrders = [
  { id: 101, table: 5, item: 'Margarita', status: 'recibido' },
  { id: 102, table: 2, item: 'Cerveza Club Colombia', status: 'recibido' },
];

const BarDisplayView = () => {
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    // En una aplicación real, te conectarías a un WebSocket para recibir pedidos 
    setOrders(incomingOrders);
  }, []);

  const updateOrderStatus = (orderId, newStatus) => {
    setOrders(orders.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
    console.log(`El pedido ${orderId} ahora está ${newStatus}`);
  };

  return (
    <div className="bar-display">
      <h1>Órdenes Activas</h1>
      <div className="orders-list">
        {orders.map(order => (
          <div key={order.id} className={`order-card ${order.status}`}>
            <h3>Mesa: {order.table}</h3>
            <p>Pedido: {order.item}</p>
            <p>Estado: <strong>{order.status.toUpperCase()}</strong></p>
            <div className="order-actions">
              <button onClick={() => updateOrderStatus(order.id, 'en preparación')}>En Preparación</button>
              <button onClick={() => updateOrderStatus(order.id, 'listo')}>Listo</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default BarDisplayView;
